import java.io.*;
import javax.servlet.*;
import javax.servlet.http.*;

public class SecureServlet extends HttpServlet {
    protected void doPost(HttpServletRequest request, HttpServletResponse response) throws ServletException, IOException {
        String userInput = request.getParameter("input");

        PrintWriter out = response.getWriter();
        out.println("<html>");
        out.println("<body>");
        out.println("<h1>Your input: " + encodeForHtml(userInput) + "</h1>"); // Encode user input
        out.println("</body>");
        out.println("</html>");
    }

    private String encodeForHtml(String input) {
        // Use OWASP ESAPI or other encoding libraries to properly encode user input for HTML context
        return org.owasp.esapi.codecs.HTMLEntityCodec.getInstance().encode(input);
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
